-smoothing: auto !important;\n}\n.reports-list {\n            list-style: none;\n            padding: 0;\n            margin: 0;\n        }\n.reports-list li {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 15px;\n            color: #000864;\n            padding: 10px 0;\n            border-bottom: 1px solid #e2e8f0;\n            display: flex;\n            align-items: center;\n            gap: 10px;\n            line-height: 1.6;\n            -webkit-font-smoothing: auto;\n        }\n.reports-list li:last-child {\n            border-bottom: none;\n        }\n.reports-list .report-icon {\n            color: #00AFF0;\n            flex-shrink: 0;\n            font-size: 14px;\n        \n            -webkit-font-smoothing: auto !important;\n}\n@media (max-width: 1024px) {\n            .beforeafter-grid {\n                grid-template-columns: 1fr;\n                max-width: 500px;\n                margin: 0 auto;\n            }\n            .beforeafter-arrow {\n                transform: rotate(90deg);\n                padding: 16px 0;\n            }\n            .products-grid {\n                grid-template-columns: 1fr;\n                max-width: 600px;\n                margin: 0 auto;\n            }\n            .selection-guide {\n                grid-template-columns: 1fr;\n                max-width: 400px;\n                margin: 48px auto 0;\n            }\n            .erp-compat-callout {\n                flex-direction: column;\n                align-items: center;\n                text-align: center;\n            }\n            .integration-visual {\n                flex-direction: column;\n            }\n            .integration-arrow {\n                transform: rotate(90deg);\n                padding: 8px 0;\n            }\n            .results-grid {\n                grid-template-columns: repeat(3, 1fr);\n            }\n            .reports-grid {\n                grid-template-columns: 1fr;\n                max-width: 500px;\n                margin: 0 auto;\n            }\n        }\n\n.section-header{text-align:center;margin-bottom:48px}\n.section-title{font-family:\'Noto Sans\', sans-serif;font-size:36px;font-weight:700;color:#000864;margin-bottom:16px}\n.section-subtitle{font-family:\'Noto Sans\', sans-serif;font-size:18px;color:#5b6b80;max-width:600px;margin:0 auto}\n@media (max-width:640px){.section-title{font-size:28px}.capabilities-grid{grid-template-columns:1fr;max-width:360px;margin-left:auto;margin-right:auto}.product-detail-cta-title{font-size:28px}.product-detail-cta-buttons{flex-direction:column}.product-detail-cta-buttons .btn-white,.product-detail-cta-buttons .btn-outline-white{width:100%;text-align:center}}\n.rep ul,.rep ol{list-style:none !important;padding:0 !important;margin:0 !important}.rep li{list-style:none !important}.rep li::before{display:none !important}\n\n\n.report-icon {\n            -webkit-font-smoothing: auto !important;\n        }\n\n.report-icon {\n            -webkit-font-smoothing: auto !important;\n        }\n\n.report-icon {\n            -webkit-font-smoothing: auto !important;\n        }\n\n.report-icon {\n            -webkit-font-smoothing: auto !important;\n        }\n\n.report-icon {\n            -webkit-font-smoothing: auto !important;\n        }\n\n.report-icon {\n            -webkit-font-smoothing: auto !important;\n        }\n\n.report-icon {\n            -webkit-font-smoothing: auto !important;\n        }\n/* === SECTION 2 === */\n.et_pb_section:has(.mes-faq){padding:60px 0 !important;background:#f8fafc !important}\n.mes-faq{-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.mes-faq p{padding-bottom:0;line-height:1.6}\n.et_pb_section .mes-faq h2{margin:0;padding:0;line-height:1.6}\n.mes-faq summary{-webkit-font-smoothing:auto}\n@media(prefers-reduced-motion:reduce){}\n/* === CTA: READY TO SEE YOUR SHOP FLOOR CLEARLY? === */\n.mes-cta-section{background:linear-gradient(135deg, #00AFF0 0%, #003CC8 100%);padding:100px 24px;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.mes-cta-section::before{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background-image:url("data:image/svg+xml,%3Csvg width=\'20\' height=\'20\' viewBox=\'0 0 20 20\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cpath d=\'M10 0v20M0 10h20\' stroke=\'%23fff\' stroke-width=\'0.5\' opacity=\'0.05\'/%3E%3C/svg%3E");pointer-events:none;z-index:1}\n.mes-cta-section::after{content:\'\';position:absolute;bottom:-20%;right:-10%;width:80%;height:80%;background:radial-gradient(ellipse at center,rgba(255,255,255,0.1) 0%,transparent 70%);pointer-events:none;z-index:1}\n.mes-cta-super-d{position:absolute;top:auto;right:-5%;bottom:-5%;left:auto;width:35%;min-height:40vh;background:url("data:image/svg+xml;base64,") no-repeat center right;background-size:contain;opacity:0.16;pointer-events:none;z-index:0;animation:superDGlow 3s ease-in-out infinite}\n@keyframes superDGlow{0%,100%{filter:drop-shadow(0 0 20px rgba(0,175,240,0.1))}50%{filter:drop-shadow(0 0 40px rgba(0,175,240,0.25))}}\n\n.mes-cta-container{position:relative;z-index:3;max-width:700px;margin:0 auto;text-align:center}\n.mes-cta-title{font-family:\'Noto Sans\',sans-serif;font-weight:700;font-size:40px;color:#fff;line-height:1.6;margin:0 0 16px}\n.mes-cta-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:20px;color:rgba(255,255,255,0.9);margin:0 0 40px}\n/* Divi overrides — ensure font properties survive Divi cascade */\n.et_pb_section .mes-cta-title{font-weight:700 !important;font-size:40px !important;line-height:1.6 !important;color:#fff !important}\n.et_pb_section .mes-cta-subtitle{font-weight:400 !important;padding-bottom:0 !important}\n.et_pb_section .mes-cta-container p{padding-bottom:0 !important}\n\n.mes-cta-btn{font-family:\'Noto Sans\',sans-serif;font-size:16px;font-weight:600;padding:16px 32px;border-radius:8px;cursor:pointer;transition:all 0.3s ease;text-decoration:none;display:inline-flex;align-items:center;gap:8px;position:relative;overflow:hidden;border:none;line-height:1.6}\n.mes-cta-btn::before{content:\'\';position:absolute;top:0;left:-100%;width:100%;height:100%;background:linear-gradient(90deg,transparent,rgba(255,255,255,0.2),transparent);transition:left 0.5s}\n.mes-cta-btn:hover::before{left:100%}\n.mes-cta-btn--primary{background:#fff;color:#003CC8;font-weight:600;box-shadow:0 4px 20px rgba(0,0,0,0.15)}\n.mes-cta-btn--primary:hover{transform:translateY(-3px);box-shadow:0 12px 40px rgba(0,0,0,0.2)}\n.mes-cta-btn--ghost{background:transparent;color:#fff;border:2px solid rgba(255,255,255,0.6)}\n.mes-cta-btn--ghost:hover{background:rgba(255,255,255,0.15);border-color:#fff}\n.mes-cta-btn-row{display:flex;gap:20px;flex-wrap:wrap;justify-content:center;position:relative;z-index:2}\n.mes-cta-btn{position:static;overflow:visible;display:inline-flex;align-items:center;gap:8px;padding:16px 32px;border-radius:8px;line-height:1.6}\n@media(max-width:767px){\n  .mes-cta-title{font-size:28px;margin-bottom:16px}\n  .mes-cta-subtitle{font-size:16px;margin-bottom:32px}\n  .mes-cta-btn-row{flex-direction:column;align-items:stretch;gap:16px}\n  .mes-cta-btn{width:100%;max-width:300px;margin:0 auto;text-align:center}\n}\n@media(prefers-reduced-motion:reduce){.mes-cta-btn{transition:none !important}.mes-cta-btn::before{display:none}}\n\n.et_pb_section:has(.mes-related-section){background:#F5F7FA;padding:0}\n.mes-related-section{padding:60px 5%;background:#F5F7FA;max-width:100%;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto}\n.mes-related-heading{font-family:\'Noto Sans\',sans-serif;font-size:28px;font-weight:600;color:#000864;margin:0 0 32px 0;padding:0;text-align:center;line-height:1.6;-webkit-font-smoothing:auto}\n.mes-related-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(280px,1fr));gap:24px;max-width:1200px;margin:0 auto}\n.mes-related-card{display:block;padding:24px;background:#fff;border-radius:12px;text-decoration:none;border:1px solid #e5e7eb;transition:box-shadow 0.3s ease;color:#333;line-height:1.6}\n.mes-related-card:hover{box-shadow:0 8px 24px rgba(0,8,100,0.1)}\n.mes-related-card-title{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:600;color:#000864;margin:0 0 8px 0;padding:0;line-height:1.6;-webkit-font-smoothing:auto}\n.mes-related-card-desc{font-family:\'Noto Sans\',sans-serif;font-size:14px;color:#666;margin:0;padding:0;line-height:1.5;-webkit-font-smoothing:auto}\n@media(prefers-reduced-motion:reduce){.mes-related-card{transition:none}}\n\n/* === TB BODY WRAPPER RESET (must be last — beats :has() rules and Divi mobile padding) === */\n/* .et-l--body doesn\'t exist on all WP/Divi versions — use [class*="tb_body"] directly */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row[class*="tb_body"].et_pb_row{padding:0 !important}\n}</style><!-- /wp:html -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hero"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hero: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hero: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="mes-hero">\n\n            <div class="mes-hero-inner">\n                <div class="mes-hero-grid">\n                    <div class="mes-hero-content">\n                        <div class="mes-hero-badge">Manufacturing Execution System</div>\n                        <h1>Stop Guessing. Start Seeing.</h1>\n                        <p class="mes-hero-subtitle">Real-time visibility into every workstation, every work order, every minute. Know exactly what\'s happening on your shop floor—as it happens.</p>\n                        <div class="mes-hero-ctas">\n                            <a href="../demo/" class="btn-white">Let\'s Talk</a>\n                            <a href="#compare" class="btn-outline-white">Find Your Fit</a>\n                        </div>\n                        <div class="mes-hero-stats">\n                            <div class="mes-hero-stat">\n                                <div class="mes-hero-stat-number dw-years">44</div>\n                                <div class="mes-hero-stat-label">Years in Mfg</div>\n                            </div>\n                            <div class="mes-hero-stat">\n                                <div class="mes-hero-stat-number">50K+</div>\n                                <div class="mes-hero-stat-label">Factories</div>\n                            </div>\n                            <div class="mes-hero-stat">\n                                <div class="mes-hero-stat-number">100+</div>\n                                <div class="mes-hero-stat-label">Thai Sites</div>\n                            </div>\n                        </div>\n                    </div>\n                    <div class="mes-hero-visual">\n                        <div class="mes-dashboard-mockup">\n                            <div class="mockup-header">\n                                <div class="mockup-dot"></div>\n                                <div class="mockup-dot"></div>\n                                <div class="mockup-dot"></div>\n                            </div>\n                            <div class="mockup-content">\n                                <div class="mockup-status-bar">\n                                    <div class="mockup-status-item">\n                                        <div class="mockup-status-value green">87%</div>\n                                        <div class="mockup-status-label">OEE</div>\n                                    </div>\n                                    <div class="mockup-status-item">\n                                        <div class="mockup-status-value">1,247</div>\n                                        <div class="mockup-status-label">Units Today</div>\n                                    </div>\n                                    <div class="mockup-status-item">\n                                        <div class="mockup-status-value yellow">3</div>\n                                        <div class="mockup-status-label">Alerts</div>\n                                    </div>\n                                </div>\n                                <div class="mockup-timeline">\n                                    <div class="mockup-bar" style="height: 40%;"></div>\n                                    <div class="mockup-bar" style="height: 65%;"></div>\n                                    <div class="mockup-bar" style="height: 55%;"></div>\n                                    <div class="mockup-bar" style="height: 80%;"></div>\n                                    <div class="mockup-bar" style="height: 70%;"></div>\n                                    <div class="mockup-bar active" style="height: 90%;"></div>\n                                    <div class="mockup-bar" style="height: 45%;"></div>\n                                </div>\n                            </div>\n                        </div>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="dw-section" style="padding: 40px 0 0; text-align: center;">\n    <div style="max-width: 800px; margin: 0 auto; padding: 0 24px;">\n        <h2 style="font-family: \'Noto Sans\', sans-serif; font-size: 22px; font-weight: 700; color: #000864; margin: 0 0 12px 0;">What is MES (Manufacturing Execution System)?</h2>\n        <p style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; line-height: 1.7; color: #333; margin: 0 0 24px 0;">\n          A Manufacturing Execution System (MES) is software that monitors, tracks, and controls production on the factory floor in real time, bridging the gap between ERP planning and shop floor execution. It gives manufacturers instant visibility into what is happening at every workstation and work order — replacing paper logs and delayed reports with live data.\n        </p>\n        <p style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; line-height: 1.7; color: #333;">\n          <strong>DigiWin MES</strong> provides this real-time visibility for factories in Thailand. Through three tiers — <strong>MES</strong> for full production execution, <strong>SFT</strong> (Shop Floor Tracking) for mid-tier tracking, and <strong>AIoT Cloud</strong> for entry-level monitoring — it tracks work orders, calculates OEE in real time, captures quality data at every station, and maintains complete lot-level traceability. Start anywhere and upgrade as your factory matures.\n        </p>\n      </div>    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Beforeafter"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Beforeafter: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Beforeafter: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="beforeafter-section">\n    <div class="beforeafter-inner">\n                <div class="section-header">\n                    <h2 class="section-title">The Transformation</h2>\n                    <p class="section-subtitle">From shop floor chaos to real-time clarity</p>\n                </div>\n    \n                <div class="beforeafter-grid">\n                    <div class="beforeafter-column before">\n                        <div class="beforeafter-header before">\n                            <div class="beforeafter-label before">Before MES</div>\n                        </div>\n                        <div class="beforeafter-content">\n                            <div class="beforeafter-item">\n                                <div class="beforeafter-item-title">"Where\'s that order?"</div>\n                                <div class="beforeafter-item-desc">Walk the floor, ask around, hope someone knows. Hours to find answers.</div>\n                            </div>\n                            <div class="beforeafter-item">\n                                <div class="beforeafter-item-title">Yesterday\'s data</div>\n                                <div class="beforeafter-item-desc">Production reports arrive after problems already happened. Always reacting.</div>\n                            </div>\n                            <div class="beforeafter-item">\n                                <div class="beforeafter-item-title">Traceability panic</div>\n                                <div class="beforeafter-item-desc">Quality issue? Days of paper-digging to find which batch, which lot, which operator.</div>\n                            </div>\n                            <div class="beforeafter-item">\n                                <div class="beforeafter-item-title">OEE guesswork</div>\n                                <div class="beforeafter-item-desc">Downtime tracking on whiteboards. No one trusts the numbers.</div>\n                            </div>\n                        </div>\n                    </div>\n    \n                    <div class="beforeafter-arrow">→</div>\n    \n                    <div class="beforeafter-column after">\n                        <div class="beforeafter-header after">\n                            <div class="beforeafter-label after">With DigiWin MES</div>\n                        </div>\n                        <div class="beforeafter-content">\n                            <div class="beforeafter-item">\n                                <div class="beforeafter-item-title">Order location in one click</div>\n                                <div class="beforeafter-item-desc">Which station, what operation, estimated completion—instant answers.</div>\n                            </div>\n                            <div class="beforeafter-item">\n                                <div class="beforeafter-item-title">Real-time dashboards</div>\n                                <div class="beforeafter-item-desc">Live production rates, quality alerts, downtime notifications. Prevent problems.</div>\n                            </div>\n                            <div class="beforeafter-item">\n                                <div class="beforeafter-item-title">Complete traceability</div>\n                                <div class="beforeafter-item-desc">Full genealogy from receiving to shipping. One click shows everything.</div>\n                            </div>\n                            <div class="beforeafter-item">\n                                <div class="beforeafter-item-title">Accurate OEE</div>\n                                <div class="beforeafter-item-desc">Automatic calculation from machine data. Real numbers you can trust.</div>\n                            </div>\n                        </div>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Products"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Products: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Products: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="products-section">\n    <div class="products-inner">\n                <div class="section-header">\n                    <h2 class="section-title">Three Paths to Shop Floor Visibility</h2>\n                    <p class="section-subtitle">Choose the level that matches your needs and budget. Start anywhere — upgrade anytime.</p>\n                </div>\n    \n                <div class="products-grid">\n                    \n                    <div class="product-box">\n                        <div class="product-box-header">\n                            <span class="product-box-badge full">Full MES</span>\n                            <h3 class="product-box-title">MES</h3>\n                            <p class="product-box-tagline">Complete manufacturing execution with routing enforcement</p>\n                        </div>\n                        <div class="product-box-content">\n                            <p class="product-box-desc">Full MES capability including work order management, routing enforcement, quality data collection, and real-time performance dashboards.</p>\n                            <ul class="product-features">\n                                <li><span class="check">✓</span> Work order dispatch and real-time tracking</li>\n                                <li><span class="check">✓</span> Routing enforcement with operation validation</li>\n                                <li><span class="check">✓</span> Quality data collection with SPC integration</li>\n                                <li><span class="check">✓</span> Real-time OEE calculation per machine/line</li>\n                                <li><span class="check">✓</span> Full lot and serial traceability</li>\n                                <li><span class="check">✓</span> Mobile workstation interface</li>\n                            </ul>\n                            <div class="product-best-for">\n                                <div class="product-best-for-label">Best For</div>\n                                <div class="product-best-for-text">Complex manufacturing with multiple operations, automotive/electronics with traceability requirements, factories with government grants or existing ERP</div>\n                            </div>\n                        </div>\n                    </div>\n    \n                    \n                    <div class="product-box">\n                        <div class="product-box-header">\n                            <span class="product-box-badge light">Mid-Tier</span>\n                            <h3 class="product-box-title">SFT</h3>\n                            <p class="product-box-tagline">Shop floor tracking without MES complexity</p>\n                        </div>\n                        <div class="product-box-content">\n                            <p class="product-box-desc">Lightweight tracking for factories that want visibility without full MES complexity. Barcode-based, fast to implement, easy to use.</p>\n                            <ul class="product-features">\n                                <li><span class="check">✓</span> Production quantity reporting</li>\n                                <li><span class="check">✓</span> Labor time tracking by operation</li>\n                                <li><span class="check">✓</span> Downtime reason recording</li>\n                                <li><span class="check">✓</span> Basic lot traceability</li>\n                                <li><span class="check">✓</span> Simple barcode scanning interface</li>\n                                <li><span class="check">✓</span> Rapid deployment (days, not months)</li>\n                            </ul>\n                            <div class="product-best-for">\n                                <div class="product-best-for-label">Best For</div>\n                                <div class="product-best-for-text">Factories already using SCADA, fast-growing companies, rapid visibility improvement without disruption</div>\n                            </div>\n                        </div>\n                    </div>\n    \n                    \n                    <div class="product-box">\n                        <div class="product-box-header">\n                            <span class="product-box-badge entry">Entry Level</span>\n                            <h3 class="product-box-title">AIoT Cloud</h3>\n                            <p class="product-box-tagline">Production visibility on a subscription</p>\n                        </div>\n                        <div class="product-box-content">\n                            <p class="product-box-desc">Cloud-based production monitoring with mobile apps. See equipment data and production status with minimal IT infrastructure.</p>\n                            <ul class="product-features">\n                                <li><span class="check">✓</span> Real-time equipment monitoring</li>\n                                <li><span class="check">✓</span> Production status dashboard</li>\n                                <li><span class="check">✓</span> Mobile app access</li>\n                                <li><span class="check">✓</span> Subscription pricing (no upfront)</li>\n                                <li><span class="check">✓</span> Cloud deployment (no servers)</li>\n                            </ul>\n                            <div class="product-best-for">\n                                <div class="product-best-for-label">Best For</div>\n                                <div class="product-best-for-text">Low initial investment, simple equipment monitoring, factories testing digitalization before committing</div>\n                            </div>\n                        </div>\n                    </div>\n                </div>\n    \n                \n                <div class="selection-guide">\n                    <div class="selection-guide-item">\n                        <div class="selection-guide-arrow">&#9650;</div>\n                        <div class="selection-guide-product">AIoT Cloud</div>\n                        <div class="selection-guide-desc">Starting your digitalization journey. Small factories, quick start, subscription pricing.</div>\n                    </div>\n                    <div class="selection-guide-item">\n                        <div class="selection-guide-arrow">&#9650;&#9650;</div>\n                        <div class="selection-guide-product">SFT</div>\n                        <div class="selection-guide-desc">Need production transparency. Mid-size operations, structured tracking, fast deployment.</div>\n                    </div>\n                    <div class="selection-guide-item">\n                        <div class="selection-guide-arrow">&#9650;&#9650;&#9650;</div>\n                        <div class="selection-guide-product">MES</div>\n                        <div class="selection-guide-desc">Full manufacturing execution. Complex operations, multi-plant, complete traceability.</div>\n                    </div>\n                </div>\n    \n                \n                <div class="erp-compat-callout">\n                    <div class="erp-compat-icon">\n                        <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M12 2v6m0 8v6M4.93 4.93l4.24 4.24m5.66 5.66l4.24 4.24M2 12h6m8 0h6M4.93 19.07l4.24-4.24m5.66-5.66l4.24-4.24"/></svg>\n                    </div>\n                    <div class="erp-compat-content">\n                        <h3>Already Have an ERP?</h3>\n                        <p>MES connects to any ERP system through standard web services. See your shop floor clearly without changing your existing ERP. When you\'re ready to upgrade, we\'re here.</p>\n                    </div>\n                </div>\n    \n                \n                <div class="workflow-strip">\n                    <h3 class="workflow-strip-title">A Day on the MES-Connected Shop Floor</h3>\n                    <div class="workflow-steps">\n                        <div class="workflow-step">\n                            <div class="workflow-step-circle">1</div>\n                            <div class="workflow-step-label">Clock In</div>\n                        </div>\n                        <div class="workflow-connector"></div>\n                        <div class="workflow-step">\n                            <div class="workflow-step-circle">2</div>\n                            <div class="workflow-step-label">Material Check</div>\n                        </div>\n                        <div class="workflow-connector"></div>\n                        <div class="workflow-step">\n                            <div class="workflow-step-circle">3</div>\n                            <div class="workflow-step-label">First QC</div>\n                        </div>\n                        <div class="workflow-connector"></div>\n                        <div class="workflow-step">\n                            <div class="workflow-step-circle">4</div>\n                            <div class="workflow-step-label">Start Machine</div>\n                        </div>\n                        <div class="workflow-connector"></div>\n                        <div class="workflow-step">\n                            <div class="workflow-step-circle">5</div>\n                            <div class="workflow-step-label">Log Production</div>\n                        </div>\n                        <div class="workflow-connector"></div>\n                        <div class="workflow-step">\n                            <div class="workflow-step-circle">6</div>\n                            <div class="workflow-step-label">Mid-Shift QC</div>\n                        </div>\n                        <div class="workflow-connector"></div>\n                        <div class="workflow-step">\n                            <div class="workflow-step-circle">7</div>\n                            <div class="workflow-step-label">Material Request</div>\n                        </div>\n                        <div class="workflow-connector"></div>\n                        <div class="workflow-step">\n                            <div class="workflow-step-circle">8</div>\n                            <div class="workflow-step-label">End Count</div>\n                        </div>\n                        <div class="workflow-connector"></div>\n                        <div class="workflow-step">\n                            <div class="workflow-step-circle">9</div>\n                            <div class="workflow-step-label">Clock Out</div>\n                        </div>\n                    </div>\n                    <p class="workflow-caption">"Every step captured. Every scan recorded. Every minute accounted for."</p>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Capabilities"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Capabilities: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desk