INSERT INTO wp_postmeta (post_id, meta_key, meta_value) VALUES (100562, '_et_pb_custom_css', '/* === GLOBAL DIVI THEME RESET === */\n.et_pb_section,.et_pb_row,.et_pb_column,.et_pb_code,.et_pb_code_inner{font-family:\'Noto Sans\',sans-serif !important;font-weight:400 !important;font-size:16px !important;color:#333 !important}\n.et_pb_section h1,.et_pb_section h2,.et_pb_section h3,.et_pb_section h4,.et_pb_section h5,.et_pb_section h6{padding-bottom:0 !important}\n.et_pb_section:not([class*=\'tb_body\']){overflow:hidden !important;margin:0 !important}\n.et_pb_row:not([class*=\'tb_body\']){max-width:100% !important;width:100% !important;padding:0 !important;margin-top:0 !important;margin-bottom:0 !important;gap:0 !important}\n.et_pb_column:not([class*=\'tb_body\']){padding:0 !important;margin:0 !important;gap:0 !important}\n.et_pb_section .et_pb_row .et_pb_column .et_pb_text.et_pb_module{margin:0 !important;padding:0 !important}\n.section-title{line-height:1.6;-webkit-font-smoothing:auto}\n.section-subtitle{margin-left:auto;margin-right:auto;line-height:1.6}\n/* fade-in / scroll-fade-in: always visible (no JS scroll observer in Divi) */\n.fade-in,.scroll-fade-in{opacity:1 !important;transform:none !important}\n/* === DIVI MOBILE ROW PADDING OVERRIDE === */\n/* Divi injects: @media(max-width:640px){.et_pb_section .et_pb_row{padding:0 24px !important}}\n   Specificity 0,2,0. We use .et_pb_row.et_pb_row (0,2,0 doubled = 0,2,0 still, but\n   .et_pb_section prefix pushes us to 0,3,0) to beat it. */\n@media(max-width:640px){\n  .et_pb_section .et_pb_row.et_pb_row{padding:0 !important}\n}\n/* === MOBILE TOUCH TARGET RESET (WCAG 2.5.8 — 44px minimum) === */\n@media(max-width:768px){\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]),\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]),\n  select,textarea{min-height:44px}\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]){display:inline-flex;align-items:center}\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]){min-height:44px}\n}\n\n@keyframes fadeIn{from{opacity:0}to{opacity:1}}\n@keyframes slide-up{from{opacity:0;transform:translateY(30px)}to{opacity:1;transform:translateY(0)}}\n@keyframes grain{0%,100%{transform:translate(0,0)}10%{transform:translate(-2%,-2%)}20%{transform:translate(2%,2%)}30%{transform:translate(-1%,1%)}40%{transform:translate(1%,-1%)}50%{transform:translate(-2%,2%)}60%{transform:translate(2%,-2%)}70%{transform:translate(-1%,-1%)}80%{transform:translate(1%,1%)}90%{transform:translate(-2%,2%)}}\n@keyframes dw-wave-drift{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n@keyframes dw-scroll{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n/* === HERO (S1) === */\n/* TODO: Review and remap class selectors to use hero prefix */\n/* TODO: Add section container: .hero-section{...;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px} */\n.mes-hero {\n            background: linear-gradient(135deg, #1a2d3d 0%, #000864 50%, #001080 100%);\n            padding: 140px 0 100px;\n            position: relative;\n            overflow: hidden;\n        }\n.mes-hero::before {\n            content: \'\';\n            position: absolute;\n            top: 0;\n            left: 0;\n            right: 0;\n            bottom: 0;\n            background: url(\'data:image/svg+xml,<svg aria-hidden="true" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 100 100"><defs><pattern id="grid" width="10" height="10" patternUnits="userSpaceOnUse"><path d="M 10 0 L 0 0 0 10" fill="none" stroke="rgba(255,255,255,0.03)" stroke-width="0.5"/></pattern></defs><rect width="100" height="100" fill="url(%23grid)"/></svg>\');\n            opacity: 0.5;\n        }\n.mes-hero-inner {\n            max-width: 1200px;\n            margin: 0 auto;\n            padding: 0 24px;\n            text-align: center;\n            position: relative;\n            z-index: 1;\n        }\n.mes-hero-badge {\n            display: inline-flex;\n            align-items: center;\n            gap: 8px;\n            background: rgba(0, 175, 240, 0.15);\n            border: 1px solid rgba(0, 175, 240, 0.3);\n            padding: 8px 20px;\n            border-radius: 50px;\n            color: #7fc4fd;\n            font-size: 11px;\n            font-weight: 500;\n            margin-bottom: 24px;\n            font-family: \'JetBrains Mono\', monospace;\n            text-transform: uppercase;\n            letter-spacing: 0.1em;\n        \n            line-height: 17.6px;\n\n            -webkit-font-smoothing: auto;\n}\n.mes-hero-stats {\n            display: flex;\n            justify-content: center;\n            gap: 48px;\n            margin-top: 40px;\n            padding-top: 32px;\n            border-top: 1px solid rgba(255, 255, 255, 0.1);\n        }\n.mes-hero-stat-number {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 32px;\n            font-weight: 800;\n            color: #00AFF0;\n        \n            line-height: 51.2px !important;\n\n            -webkit-font-smoothing: auto !important;\n}\n.mes-hero-stat-label {\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 10px;\n            color: rgba(255, 255, 255, 0.75);\n            text-transform: uppercase;\n            letter-spacing: 0.1em;\n            margin-top: 4px;\n        \n            line-height: 16px !important;\n\n            -webkit-font-smoothing: auto !important;\n}\n.mes-hero-grid {\n            display: grid;\n            grid-template-columns: 1fr 1fr;\n            gap: 60px;\n            align-items: center;\n            text-align: left;\n        }\n.mes-hero-content {\n            max-width: 560px;\n        }\n.mes-hero-visual {\n            position: relative;\n        }\n.mes-dashboard-mockup {\n            background: rgba(255, 255, 255, 0.03);\n            border: 1px solid rgba(255, 255, 255, 0.1);\n            border-radius: 16px;\n            padding: 20px;\n            box-shadow: 0 40px 80px rgba(0, 0, 0, 0.3);\n        }\n.mockup-content {\n            background: rgba(0, 0, 0, 0.2);\n            border-radius: 8px;\n            padding: 16px;\n        }\n.mockup-status-bar {\n            display: flex;\n            gap: 12px;\n            margin-bottom: 16px;\n        }\n.mockup-status-item {\n            flex: 1;\n            background: rgba(255, 255, 255, 0.05);\n            border-radius: 8px;\n            padding: 12px;\n            text-align: center;\n        }\n.mockup-status-value {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 20px;\n            font-weight: 700;\n            color: #00AFF0;\n        \n            line-height: 32px !important;\n\n            -webkit-font-smoothing: auto !important;\n}\n.mockup-status-value.green { color: #047857; }\n.mockup-status-value.yellow { color: #f59e0b; }\n.mockup-status-label {\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 9px;\n            color: rgba(255, 255, 255, 0.75);\n            text-transform: uppercase;\n            margin-top: 4px;\n        \n            line-height: 14.4px !important;\n\n            -webkit-font-smoothing: auto !important;\n}\n.mockup-timeline {\n            display: flex;\n            gap: 8px;\n            align-items: flex-end;\n            height: 60px;\n            padding: 8px;\n            background: rgba(255, 255, 255, 0.03);\n            border-radius: 6px;\n        }\n.mockup-header {\n            display: flex;\n            gap: 8px;\n            margin-bottom: 16px;\n        }\n.mockup-dot {\n            width: 12px;\n            height: 12px;\n            border-radius: 50%;\n        }\n.mockup-dot:nth-child(1) { background: #ff5f57; }\n.mockup-dot:nth-child(2) { background: #ffbd2e; }\n.mockup-dot:nth-child(3) { background: #28ca42; }\n.mockup-bar {\n            flex: 1;\n            background: #00AFF0;\n            border-radius: 4px 4px 0 0;\n            opacity: 0.6;\n        }\n.mockup-bar.active {\n            opacity: 1;\n            background: #10b981;\n        }\n.mes-hero h1 {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 48px;\n            font-weight: 700;\n            color: #ffffff;\n            margin-bottom: 20px;\n            line-height: 1.15;\n        }\n.mes-hero-subtitle {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 20px;\n            color: rgba(255, 255, 255, 0.85);\n            max-width: 700px;\n            margin: 0 auto 32px;\n            line-height: 1.6;\n        \n            -webkit-font-smoothing: auto;\n}\n.mes-hero-ctas {\n            display: flex;\n            gap: 16px;\n            justify-content: center;\n            flex-wrap: wrap;\n        }\n.integration-node.active {\n            border-color: #00AFF0;\n            background: linear-gradient(135deg, #f0f7ff 0%, #ffffff 100%);\n            box-shadow: 0 8px 24px rgba(0, 175, 240, 0.15);\n        }\n@media (max-width: 1024px) {\n            .mes-hero-grid {\n                grid-template-columns: 1fr;\n                text-align: center;\n            }\n            .mes-hero-content {\n                max-width: 100%;\n            }\n            .mes-hero-visual {\n                display: none;\n            }\n            .mes-hero-stats {\n                justify-content: center;\n            }\n        }\n@media (max-width: 640px) {\n            .mes-hero {\n                padding: 120px 0 60px;\n            }\n            .mes-hero h1 {\n                font-size: 32px;\n            }\n            .results-grid {\n                grid-template-columns: 1fr;\n                max-width: 280px;\n                margin: 0 auto 32px;\n            }\n        }\n@media (prefers-reduced-motion: reduce) {\n            .product-box,\n            .integration-node,\n            .integration-link,\n            .dw-wave-flow {\n                animation: none !important;\n                transition: none !important;\n            }\n        }\n\n/* TODO: HOVER STATES using global classes (port manually) */\n/* .dw-nav-item.active .dw-nav-link svg,.dw-nav-item:hover .dw-nav-link svg{transform:rotate(180deg)} */\n/* Buttons */\n.btn-white{background:#ffffff;color:#003CC8;padding:20px 40px;border-radius:14px;font-family:\'Noto Sans\', sans-serif;font-size:16px;font-weight:600;text-decoration:none;transition:all 0.4s cubic-bezier(0.4, 0, 0.2, 1);box-shadow:0 4px 20px rgba(0, 0, 0, 0.15);display:inline-flex;align-items:center;gap:10px\n            line-height: 25.6px!important;\n\n            -webkit-font-smoothing: auto;\n}\n.btn-white:hover{transform:translateY(-4px);box-shadow:0 16px 48px rgba(0, 0, 0, 0.2)}\n.btn-outline-white{background:transparent;color:#ffffff;padding:20px 40px;border-radius:14px;border:2px solid rgba(255, 255, 255, 0.5);font-family:\'Noto Sans\', sans-serif;font-size:16px;font-weight:600;text-decoration:none;transition:all 0.3s ease\n            line-height: 25.6px!important;\n\n            -webkit-font-smoothing: auto;\n}\n.btn-outline-white:hover{background:rgba(255, 255, 255, 0.15);border-color:#ffffff}\n/* TODO: PSEUDO-ELEMENTS using global classes (port manually) */\n/* .dw-nav-item.active .dw-nav-link::after{transform:scaleX(1)} */\n/* Defensive SVG sizing */\nsvg:not([width]):not([class]){max-width:48px;max-height:48px}\n@media(prefers-reduced-motion:reduce){}\n\n.mes-hero-stat-label {\n            line-height: 16px !important;\n        \n            -webkit-font-smoothing: auto !important;\n}\n\n.mes-hero-stat-number {\n            line-height: 51.2px !important;\n        \n            -webkit-font-smoothing: auto !important;\n}\n\n.mes-hero-stat-label {\n            line-height: 16px !important;\n        \n            -webkit-font-smoothing: auto !important;\n}\n\n.mockup-status-value {\n            line-height: 32px !important;\n        \n            -webkit-font-smoothing: auto !important;\n}\n\n.mockup-status-label {\n            line-height: 14.4px !important;\n        \n            -webkit-font-smoothing: auto !important;\n}\n\n.mockup-status-label {\n            line-height: 14.4px !important;\n        \n            -webkit-font-smoothing: auto !important;\n}\n\n.mes-hero-stat-number {\n            line-height: 51.2px !important;\n        \n            -webkit-font-smoothing: auto !important;\n}\n\n.mockup-status-value {\n            line-height: 32px !important;\n        \n            -webkit-font-smoothing: auto !important;\n}\n\n\n.et_pb_section .btn-white {\n            line-height: 25.6px !important;\n        }\n\n.et_pb_section .btn-outline-white {\n            line-height: 25.6px !important;\n        }\n/* === SECTION (S2) === */\n/* TODO: Review and remap class selectors to use sec prefix */\n/* TODO: Add section container: .dw-section{...;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px} */\n\n\n/* TODO: PSEUDO-ELEMENTS using global classes (port manually) */\n/* .dw-section--blue::before{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background:radial-gradient(ellipse at 20% 30%, rgba(255,255,255,0.15) 0%, transparent 50%);pointer-events:none} */\n@media(prefers-reduced-motion:reduce){}\n/* === BEFOREAFTER (S3) === */\n/* TODO: Review and remap class selectors to use bef prefix */\n/* TODO: Add section container: .beforeafter-section{...;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px} */\n.beforeafter-section {\n            padding: 80px 0;\n            background: #ffffff;\n        }\n.beforeafter-inner {\n            max-width: 1200px;\n            margin: 0 auto;\n            padding: 0 24px;\n        }\n.beforeafter-grid {\n            display: grid;\n            grid-template-columns: 1fr 60px 1fr;\n            gap: 24px;\n            align-items: start;\n        }\n.beforeafter-column {\n         